-- ============================================================
-- Lohikeitto: combined schema + seed migration
-- ============================================================

CREATE EXTENSION IF NOT EXISTS pg_trgm;

CREATE TABLE service_localizations (
    id       UUID PRIMARY KEY,
    bg       TEXT,
    cs       TEXT,
    da       TEXT,
    de       TEXT,
    el       TEXT,
    en       TEXT,
    es       TEXT,
    fi       TEXT,
    fil      TEXT,
    fr       TEXT,
    hi       TEXT,
    hu       TEXT,
    is_      TEXT,
    it       TEXT,
    ja       TEXT,
    ka       TEXT,
    kk       TEXT,
    ko       TEXT,
    nb       TEXT,
    nl       TEXT,
    pl       TEXT,
    pt_br    TEXT,
    ro       TEXT,
    ru       TEXT,
    sk       TEXT,
    sr       TEXT,
    sv       TEXT,
    th       TEXT,
    uk       TEXT,
    vi       TEXT,
    zh_hans  TEXT,
    zh_hant  TEXT
);

CREATE TABLE services (
    id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name            TEXT NOT NULL,
    slug            TEXT NOT NULL UNIQUE,
    category        TEXT NOT NULL,
    colors          JSONB NOT NULL,
    links           JSONB NOT NULL DEFAULT '{}',
    locales         JSONB NOT NULL DEFAULT '[]',
    localization_id UUID REFERENCES service_localizations(id),
    default_locale  TEXT NOT NULL DEFAULT 'en',
    ref_link        TEXT,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT now()
);

